mapper.update:
UPDATE fcm_token
SET token = #{token},
     expired_at = #{expiredAt},
     is_expired = false
WHERE device_id = #{deviceId}
    AND member_id = #{memberId}

mapper.delete:
DELETE FROM fcm_token
WHERE member_id = #{memberId}
    AND device_id = #{deviceId}

mapper.select:
SELECT count(*)
FROM fcm_token
WHERE member_id = #{memberId}
AND   device_id = #{deviceId}
